#include <stdio.h>
#include <stdlib.h>
#define MAX_M 100
#define MAX_N 100
#define MAX_D 20000

int min_toll_cost[MAX_M][MAX_N];
int movement_cost[MAX_M][MAX_M];

int calculate_min_toll_cost(int D, int n, int m, int toll_cost[MAX_M][MAX_N], int movement_cost[MAX_M][MAX_M]) {
    // Calculate the minimum toll cost for each road
    for (int i = 0; i < m; i++) {
        min_toll_cost[i][0] = toll_cost[i][0];
        for (int j = 1; j < n; j++) {
            min_toll_cost[i][j] = min_toll_cost[i][j - 1] + toll_cost[i][j];
        }
    }

    // Apply a greedy approach to find the maximum amount that can be spent on a caravan
    int max_amount = -1;
    for (int i = 0; i < m; i++) {
        int current_amount = D;
        for (int j = 0; j < n; j++) {
            current_amount -= toll_cost[i][j];
            if (current_amount < 0) break;
        }
        if (current_amount >= 0) {
            max_amount = (max_amount > current_amount) ? max_amount : current_amount;
        }
    }

    return max_amount;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int D, n, m;
        scanf("%d %d %d", &D, &n, &m);
        int toll_cost[MAX_M][MAX_N];
        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {
                scanf("%d", &toll_cost[i][j]);
            }
        }
        for (int i = 0; i < m; i++) {
            for (int j = 0; j < m; j++) {
                scanf("%d", &movement_cost[i][j]);
            }
        }
        printf("%d\n", calculate_min_toll_cost(D, n, m, toll_cost, movement_cost));
    }
    return 0;
}

